import java.io.File;
import java.util.Scanner;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a directory name to list its contents: ");
        String directory = scanner.nextLine();

        // Validate user input to ensure it is a valid directory
        File dir = new File(directory);
        if (!dir.isDirectory()) {
            System.err.println("Invalid directory. Please enter a valid directory path.");
            return;
        }

        try {
            ProcessBuilder processBuilder = new ProcessBuilder();
            processBuilder.command("ls", directory);

            Process process = processBuilder.start();
            process.waitFor();

            Scanner outputScanner = new Scanner(process.getInputStream());
            while (outputScanner.hasNextLine()) {
                System.out.println(outputScanner.nextLine());
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

